{"action":"create","path":"game/scripts/GameManager.gd","content":"extends Node

# Game Manager - Autoload Singleton
var score: int = 0
var high_score: int = 0
var lives: int = 3
var level: int = 1
var game_active: bool = false

signal score_changed(new_score)
signal lives_changed(new_lives)
signal game_over
signal level_up(new_level)

func _ready():
	pass

func start_game():
	score = 0
	lives = 3
	level = 1
	game_active = true
	emit_signal("score_changed", score)
	emit_signal("lives_changed", lives)

func add_score(points: int):
	if not game_active:
		return
	score += points
	if score > high_score:
		high_score = score
	emit_signal("score_changed", score)
	# Level up every 500 points
	var new_level = int(score / 500) + 1
	if new_level > level:
		level = new_level
		emit_signal("level_up", level)

func lose_life():
	if not game_active:
		return
	lives -= 1
	emit_signal("lives_changed", lives)
	if lives <= 0:
		game_active = false
		emit_signal("game_over")

func get_score() -> int:
	return score

func get_lives() -> int:
	return lives

func get_level() -> int:
	return level

func get_high_score() -> int:
	return high_score
"}

{"action":"create","path":"game/scripts/Player.gd","content":"extends Area2D

@export var speed: float = 300.0
@export var bullet_scene: PackedScene
@export var fire_rate: float = 0.25

var screen_size: Vector2
var can_shoot: bool = true
var is_alive: bool = true
var invincible: bool = false
var invincible_timer: float = 0.0
const INVINCIBLE_TIME: float = 2.0

@onready var shoot_timer = $ShootTimer
@onready var sprite = $Sprite2D
@onready var collision = $CollisionShape2D
@onready var engine_particles = $EngineParticles

signal player_hit

func _ready():
	screen_size = get_viewport_rect().size
	position = Vector2(screen_size.x / 2, screen_size.y - 100)


func _process(delta: float):
	if not is_alive:
		return
	_handle_movement(delta)
	_handle_shooting()
	_handle_invincibility(delta)
	_clamp_position()

func _handle_movement(delta: float):
	var velocity = Vector2.ZERO
	if Input.is_action_pressed("ui_left"):
		velocity.x -= 1
	if Input.is_action_pressed("ui_right"):
		velocity.x += 1
	if Input.is_action_pressed("ui_up"):
		velocity.y -= 1
	if Input.is_action_pressed("ui_down"):
		velocity.y += 1
	if velocity.length() > 0:
		velocity = velocity.normalized() * speed
	position += velocity * delta

func _handle_shooting():
	if Input.is_action_pressed("ui_accept") and can_shoot:
		shoot()

func _handle_invincibility(delta: float):
	if invincible:
		invincible_timer -= delta
		# Blinking effect
		sprite.modulate.a = 0.3 if int(invincible_timer * 10) % 2 == 0 else 1.0
		if invincible_timer <= 0:
			invincible = false
			sprite.modulate.a = 1.0

func _clamp_position():
	position.x = clamp(position.x, 30, screen_size.x - 30)
	position.y = clamp(position.y, 30, screen_size.y - 30)

func shoot():
	if bullet_scene == null:
		return
	can_shoot = false
	var bullet = bullet_scene.instantiate()
	bullet.position = position + Vector2(0, -40)
	get_parent().add_child(bullet)
	shoot_timer.start(fire_rate)

func _on_shoot_timer_timeout():
	can_shoot = true

func take_hit():
	if invincible or not is_alive:
		return
	invincible = true
	invincible_timer = INVINCIBLE_TIME
	emit_signal("player_hit")

func die():
	is_alive = false
	sprite.modulate = Color(1, 0, 0, 0)
	collision.set_deferred("disabled", true)

func _on_area_entered(area):
	if area.is_in_group("enemy_bullets") or area.is_in_group("enemies"):
		take_hit()
"}

